const websiteStack = new WebsiteStack(app, 'SuperSolarWebsiteStack', {
  env: { account, region: 'ap-southeast-2' },
  certificateArn,
  crossRegionReferences: true,
  description: 'Super Solar Energy — S3 + CloudFront + API + Route53',
  tags: {
    Project: 'SuperSolarEnergy',
    Owner: 'Manish Mitra',
    Environment: 'Production',
  },
});

cdk.Tags.of(app).add('ManagedBy', 'CDK');

