@import "tailwindcss";

/* ===============================================================================
   SUPER SOLAR ENERGY - Design System
   Vibrant Orange & Blue theme inspired by the Super Solar Energy logo
   =============================================================================== */

:root {
  /* Primary Brand Colors - Vibrant Orange (from sun/rays in logo) */
  --primary-orange: #E8621A;
  --primary-orange-dark: #c74f12;
  --primary-orange-light: #f47738;

  /* Secondary Colors - Solar Blue (from panels in logo) */
  --secondary-blue: #1565C0;
  --secondary-blue-dark: #0d47a1;
  --secondary-blue-light: #1e88e5;

  /* Accent Colors - Golden Yellow (from sun) */
  --accent-yellow: #F9A825;
  --accent-yellow-dark: #e09000;
  --accent-gold: #FFB300;

  /* Nature Green (from leaf in logo) */
  --nature-green: #43A047;
  --nature-green-dark: #2e7d32;
  --nature-green-light: #66bb6a;

  /* Background Colors */
  --bg-white: #ffffff;
  --bg-light: #f8f9fa;
  --bg-gray: #f0f2f5;
  --bg-orange: #E8621A;
  --bg-blue: #1565C0;

  /* Text Colors */
  --text-dark: #1a2332;
  --text-body: #3d4852;
  --text-secondary: #606f7b;
  --text-muted: #8795a1;
  --text-light: #ffffff;
  --text-heading-dark: #0f1923;

  /* Border Colors */
  --border-light: #e2e8f0;
  --border-medium: #cbd5e0;

  /* Semantic Colors */
  --background: var(--bg-white);
  --foreground: var(--text-body);
  --primary: var(--primary-orange);
  --secondary: var(--secondary-blue);

  /* Solar theme variables */
  --solar-gold: #FFB300;
  --solar-amber: #FF8F00;
  --solar-orange: #E8621A;
  --solar-glow: #FFC107;
  --energy-blue: #1565C0;
  --energy-teal: #00897B;
  --energy-emerald: #43A047;

  /* Glass Effects for light theme */
  --glass-white: rgba(255, 255, 255, 0.92);
  --glass-border: rgba(0, 0, 0, 0.08);
}

@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
}

/* ===============================================================================
   BASE STYLES
   =============================================================================== */

html {
  scroll-behavior: smooth;
  scroll-padding-top: 100px;
}

body {
  background: var(--bg-white);
  color: var(--text-body);
  font-family: 'Plus Jakarta Sans', system-ui, -apple-system, sans-serif;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  overflow-x: hidden;
}

::selection {
  background-color: rgba(232, 98, 26, 0.2);
  color: var(--primary-orange);
}

/* ===============================================================================
   SECTION BACKGROUNDS
   =============================================================================== */

.section-white {
  background: var(--bg-white);
}

.section-gray {
  background: var(--bg-gray);
}

.section-orange {
  background: var(--primary-orange);
  color: var(--text-light);
}

.section-blue {
  background: var(--secondary-blue);
  color: var(--text-light);
}

.section-yellow {
  background: var(--accent-yellow);
  color: var(--text-heading-dark);
}

.cosmic-bg {
  position: relative;
  background: var(--bg-white);
}

.cosmic-bg::before {
  display: none;
}

/* ===============================================================================
   TYPOGRAPHY
   =============================================================================== */

.heading-display {
  font-family: 'Syne', 'Plus Jakarta Sans', system-ui, sans-serif;
  font-weight: 800;
  letter-spacing: -0.03em;
  line-height: 1.1;
  color: var(--text-dark);
}

.text-gradient-solar {
  background: linear-gradient(135deg, var(--primary-orange) 0%, var(--accent-yellow) 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.text-gradient-energy {
  background: linear-gradient(135deg, var(--secondary-blue) 0%, var(--secondary-blue-light) 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.text-gradient-premium {
  background: linear-gradient(135deg, var(--primary-orange) 0%, var(--secondary-blue) 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.text-display-xl {
  font-size: clamp(2.5rem, 8vw, 5rem);
}

.text-display-lg {
  font-size: clamp(2rem, 6vw, 4rem);
}

.text-display-md {
  font-size: clamp(1.5rem, 4vw, 2.5rem);
}

/* ===============================================================================
   GLASS MORPHISM
   =============================================================================== */

.glass {
  background: rgba(255, 255, 255, 0.92);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  border: 1px solid var(--glass-border);
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.06);
}

.glass-elevated {
  background: rgba(255, 255, 255, 0.96);
  backdrop-filter: blur(24px);
  -webkit-backdrop-filter: blur(24px);
  border: 1px solid rgba(0, 0, 0, 0.06);
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.1);
}

.glass-solar {
  background: rgba(232, 98, 26, 0.08);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  border: 1px solid rgba(232, 98, 26, 0.2);
}

/* ===============================================================================
   BUTTONS & CTAs
   =============================================================================== */

.btn-solar {
  position: relative;
  background: var(--primary-orange);
  color: var(--text-light);
  font-weight: 700;
  padding: 1rem 2rem;
  border-radius: 8px;
  overflow: hidden;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  box-shadow: 0 4px 15px rgba(232, 98, 26, 0.35);
  border: none;
}

.btn-solar::before {
  content: '';
  position: absolute;
  top: 0;
  left: -100%;
  width: 100%;
  height: 100%;
  background: linear-gradient(90deg, transparent, rgba(255,255,255,0.3), transparent);
  transition: left 0.5s ease;
}

.btn-solar:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 25px rgba(232, 98, 26, 0.45);
  background: var(--primary-orange-dark);
}

.btn-solar:hover::before {
  left: 100%;
}

.btn-energy {
  position: relative;
  background: var(--secondary-blue);
  color: var(--text-light);
  font-weight: 600;
  padding: 1rem 2rem;
  border-radius: 8px;
  border: none;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  box-shadow: 0 4px 15px rgba(21, 101, 192, 0.3);
}

.btn-energy:hover {
  background: var(--secondary-blue-dark);
  transform: translateY(-2px);
  box-shadow: 0 8px 25px rgba(21, 101, 192, 0.4);
}

.btn-ghost {
  background: transparent;
  color: var(--primary-orange);
  font-weight: 600;
  padding: 1rem 2rem;
  border-radius: 8px;
  border: 2px solid var(--primary-orange);
  transition: all 0.3s ease;
}

.btn-ghost:hover {
  background: var(--primary-orange);
  color: var(--text-light);
}

/* ===============================================================================
   CARDS
   =============================================================================== */

.card-cosmic {
  background: var(--bg-white);
  border: 1px solid var(--border-light);
  border-radius: 16px;
  padding: 2rem;
  transition: all 0.4s cubic-bezier(0.4, 0, 0.2, 1);
  position: relative;
  overflow: hidden;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.06);
}

.card-cosmic::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 4px;
  background: linear-gradient(90deg, var(--primary-orange), var(--accent-yellow));
  opacity: 0;
  transition: opacity 0.4s ease;
}

.card-cosmic:hover {
  transform: translateY(-8px);
  box-shadow: 0 20px 40px rgba(0, 0, 0, 0.12);
}

.card-cosmic:hover::before {
  opacity: 1;
}

.card-blue {
  background: var(--secondary-blue);
  color: var(--text-light);
  border-radius: 16px;
  padding: 2rem;
}

.card-yellow {
  background: var(--accent-yellow);
  color: var(--text-heading-dark);
  border-radius: 16px;
  padding: 2rem;
}

.card-feature {
  background: var(--bg-white);
  border: 1px solid var(--border-light);
  border-radius: 16px;
  padding: 2.5rem;
  position: relative;
  overflow: hidden;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.06);
}

.card-feature:hover {
  box-shadow: 0 12px 40px rgba(0, 0, 0, 0.1);
}

.card-battery {
  background: var(--bg-white);
  border: 1px solid var(--border-light);
  border-radius: 16px;
  position: relative;
  overflow: hidden;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.06);
}

.card-battery::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  width: 4px;
  height: 100%;
  background: linear-gradient(180deg, var(--primary-orange), var(--accent-yellow));
}

/* ===============================================================================
   ANIMATIONS
   =============================================================================== */

@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(30px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.animate-fade-in-up {
  animation: fadeInUp 0.8s cubic-bezier(0.4, 0, 0.2, 1) forwards;
}

@keyframes scaleIn {
  from {
    opacity: 0;
    transform: scale(0.9);
  }
  to {
    opacity: 1;
    transform: scale(1);
  }
}

.animate-scale-in {
  animation: scaleIn 0.6s cubic-bezier(0.4, 0, 0.2, 1) forwards;
}

